def test_rate_limited_export_returns_429(hr_admin_token, api_client, rate_limit_threshold):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    responses = []
    for _ in range(rate_limit_threshold + 1):
        r = api_client.get("/api/employees/export.csv", headers=headers)
        responses.append(r)
        if r.status_code == 429:
            break

    last = responses[-1]
    assert last.status_code == 429, f"Expected 429, got {last.status_code}"
    assert (
        "Retry-After" in last.headers or "retry-after" in last.headers
    ), "429 must include Retry-After header"
